create extension if not exists pgcrypto;
create table if not exists public.crm_companies(id uuid primary key default gen_random_uuid(),organization_id uuid not null references public.organizations(id) on delete cascade,name text not null,registration_number text,vat_number text,website text,industry text,email text,phone text,address_line1 text,address_line2 text,postal_code text,city text,country text default 'NL',owner_id uuid references auth.users(id),status text not null default 'active',created_at timestamptz not null default now(),updated_at timestamptz not null default now(),deleted_at timestamptz);
create table if not exists public.crm_contacts(id uuid primary key default gen_random_uuid(),organization_id uuid not null references public.organizations(id) on delete cascade,company_id uuid references public.crm_companies(id) on delete set null,first_name text,last_name text,display_name text,email text,phone text,mobile text,job_title text,notes text,owner_id uuid references auth.users(id),status text not null default 'active',created_at timestamptz not null default now(),updated_at timestamptz not null default now(),deleted_at timestamptz);
create table if not exists public.crm_leads(id uuid primary key default gen_random_uuid(),organization_id uuid not null references public.organizations(id) on delete cascade,contact_id uuid references public.crm_contacts(id) on delete set null,company_id uuid references public.crm_companies(id) on delete set null,title text not null,value numeric(14,2) not null default 0,currency text not null default 'EUR',owner_id uuid references auth.users(id),source text,expected_close_date date,stage text not null default 'new',probability int not null default 10,status text not null default 'open',created_at timestamptz not null default now(),updated_at timestamptz not null default now(),deleted_at timestamptz);
create table if not exists public.crm_tasks(id uuid primary key default gen_random_uuid(),organization_id uuid not null references public.organizations(id) on delete cascade,workspace_id uuid references public.workspaces(id) on delete set null,title text not null,description text,due_at timestamptz,priority text not null default 'normal',owner_id uuid references auth.users(id),contact_id uuid references public.crm_contacts(id) on delete cascade,company_id uuid references public.crm_companies(id) on delete cascade,lead_id uuid references public.crm_leads(id) on delete cascade,status text not null default 'open',completed_at timestamptz,created_by uuid references auth.users(id),created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table if not exists public.crm_labels(id uuid primary key default gen_random_uuid(),organization_id uuid not null references public.organizations(id) on delete cascade,name text not null,color text,description text,created_at timestamptz not null default now(),unique(organization_id,name));
create table if not exists public.crm_timeline(id uuid primary key default gen_random_uuid(),organization_id uuid not null references public.organizations(id) on delete cascade,workspace_id uuid references public.workspaces(id) on delete set null,contact_id uuid references public.crm_contacts(id) on delete cascade,company_id uuid references public.crm_companies(id) on delete cascade,lead_id uuid references public.crm_leads(id) on delete cascade,type text not null,title text,body text,metadata jsonb not null default '{}'::jsonb,created_by uuid references auth.users(id),created_at timestamptz not null default now());
create index if not exists crm_contacts_org_idx on public.crm_contacts(organization_id);create index if not exists crm_companies_org_idx on public.crm_companies(organization_id);create index if not exists crm_leads_org_stage_idx on public.crm_leads(organization_id,stage);create index if not exists crm_tasks_org_due_idx on public.crm_tasks(organization_id,due_at);create index if not exists crm_timeline_org_created_idx on public.crm_timeline(organization_id,created_at desc);
alter table public.crm_contacts enable row level security;alter table public.crm_companies enable row level security;alter table public.crm_leads enable row level security;alter table public.crm_tasks enable row level security;alter table public.crm_labels enable row level security;alter table public.crm_timeline enable row level security;
do $$ declare t text; begin foreach t in array array['crm_contacts','crm_companies','crm_leads','crm_tasks','crm_labels','crm_timeline'] loop execute format('drop policy if exists crm_org_access on public.%I',t);execute format('create policy crm_org_access on public.%I for all using (exists(select 1 from public.organization_members m where m.organization_id=%I.organization_id and m.user_id=auth.uid())) with check (exists(select 1 from public.organization_members m where m.organization_id=%I.organization_id and m.user_id=auth.uid()))',t,t,t);end loop;end $$;